import { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useSubscription } from '../../context/SubscriptionContext';
import { getDeviceId, getDeviceName } from '../../utils/deviceInfo';
import { supabase } from '../../lib/supabase';
import Loader from '../ui/Loader';
import DeviceLimit from '../../pages/shop/DeviceLimit';

interface SessionGuardProps {
  children: React.ReactNode;
}

export default function SessionGuard({ children }: SessionGuardProps) {
  const { user, loading: authLoading, isAdmin } = useAuth();
  const { subscription, loading: subLoading } = useSubscription();
  const [isAuthorized, setIsAuthorized] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  const deviceId = getDeviceId();
  const deviceName = getDeviceName();

  useEffect(() => {
    const checkSession = async () => {
      if (authLoading || subLoading) return;

      if (!user) {
        setIsAuthorized(true);
        setLoading(false);
        return;
      }

      // Admin or specific roles might bypass this if needed
      // but usually even admin wants to see their devices
      if (isAdmin) {
         setIsAuthorized(true);
         setLoading(false);
         return;
      }

      try {
        // 1. Get Plan Limit
        // features.max_devices might be null, number, or undefined
        const planLimit = (subscription?.plan?.features as any)?.max_devices ?? 1;

        // 2. Refresh current device record (heartbeat)
        const { data: currentSession } = await supabase
          .from('user_sessions')
          .select('*')
          .eq('user_id', user.id)
          .eq('device_id', deviceId)
          .maybeSingle();

        if (currentSession) {
          // Update last active
          await supabase
            .from('user_sessions')
            .update({ last_active_at: new Date().toISOString() })
            .eq('id', currentSession.id);

          setIsAuthorized(true);
        } else {
          // 3. Check total session count
          const { count, error: countError } = await supabase
            .from('user_sessions')
            .select('*', { count: 'exact', head: true })
            .eq('user_id', user.id);

          if (countError) throw countError;

          if (count !== null && count < (planLimit === -1 ? Infinity : planLimit)) {
            // Register this device
            const { error: regError } = await supabase
              .from('user_sessions')
              .insert([{
                user_id: user.id,
                device_id: deviceId,
                device_name: deviceName
              }]);

            if (regError) throw regError;
            setIsAuthorized(true);
          } else {
            setIsAuthorized(false);
          }
        }
      } catch (err) {
        console.error('[SessionGuard] Error:', err);
        // TC-012 FIX: Fail-CLOSED — deny access on DB errors instead of granting it
        setIsAuthorized(false);
      } finally {
        setLoading(false);
      }
    };

    checkSession();
  }, [user, authLoading, subLoading, subscription, isAdmin]);

  if (loading || authLoading || subLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950">
        <Loader />
      </div>
    );
  }

  if (isAuthorized === false) {
    return <DeviceLimit />;
  }

  return <>{children}</>;
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Smartphone, LogOut, Terminal, RefreshCcw, ShieldCheck } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { getDeviceId } from '../../utils/deviceInfo';
import { toast } from 'sonner';

export default function SessionManager() {
  const { user } = useAuth();
  const [sessions, setSessions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const currentDeviceId = getDeviceId();

  const fetchSessions = async () => {
    if (!user) return;
    setLoading(true);
    const { data, error } = await supabase
      .from('user_sessions')
      .select('*')
      .eq('user_id', user.id)
      .order('last_active_at', { ascending: false });

    if (!error) setSessions(data || []);
    setLoading(false);
  };

  useEffect(() => {
    fetchSessions();
  }, [user]);

  const handleDeactivate = async (sessionId: string) => {
    setActionLoading(sessionId);
    const { error } = await supabase
      .from('user_sessions')
      .delete()
      .eq('id', sessionId);

    if (error) {
      toast.error('Session terminate karne mein error aaya');
    } else {
      toast.success('Session successfully terminated');
      await fetchSessions();
    }
    setActionLoading(null);
  };

  if (loading && sessions.length === 0) {
    return (
      <div className="p-10 flex flex-col items-center justify-center space-y-4">
        <RefreshCcw size={24} className="animate-spin text-brand-primary" />
        <p className="text-[10px] font-black uppercase tracking-widest text-slate-500">Syncing Sessions...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between px-2">
        <div className="flex flex-col">
          <h3 className="text-sm font-black text-white uppercase italic tracking-tighter">Security Protocol</h3>
          <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Active Device Terminals</p>
        </div>
        <button 
          onClick={fetchSessions} 
          disabled={loading}
          className={`p-2 rounded-xl bg-white/5 border border-white/10 hover:border-white/20 transition-all ${loading ? 'animate-spin' : ''}`}
        >
          <RefreshCcw size={14} className="text-slate-400" />
        </button>
      </div>

      <div className="space-y-3">
        <AnimatePresence mode="popLayout">
          {sessions.map((session) => (
            <motion.div
              key={session.id}
              layout
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className={`p-4 rounded-2xl border transition-all flex items-center justify-between group ${
                session.device_id === currentDeviceId 
                  ? 'bg-brand-primary/5 border-brand-primary/20 shadow-glow-green/5' 
                  : 'bg-white/5 border-white/5 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-4">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                  session.device_id === currentDeviceId ? 'bg-brand-primary/10 text-brand-primary' : 'bg-white/10 text-slate-400'
                }`}>
                  <Terminal size={18} />
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <p className="text-[11px] font-black uppercase tracking-widest text-white italic">
                      {session.device_name}
                    </p>
                    {session.device_id === currentDeviceId && (
                      <div className="flex items-center gap-1.5 px-2 py-0.5 bg-brand-primary/20 text-brand-primary rounded-full border border-brand-primary/20">
                        <div className="w-1 h-1 rounded-full bg-brand-primary animate-pulse" />
                        <span className="text-[7px] font-black uppercase tracking-widest">Active</span>
                      </div>
                    )}
                  </div>
                  <div className="flex items-center gap-3 mt-1">
                    <p className="text-[8px] font-bold text-slate-500 uppercase tracking-tighter italic">
                      Linked: {new Date(session.created_at).toLocaleDateString()}
                    </p>
                    <div className="w-1 h-1 rounded-full bg-white/10" />
                    <p className="text-[8px] font-bold text-slate-500 uppercase tracking-tighter italic">
                      Pulse: {new Date(session.last_active_at).toLocaleTimeString()}
                    </p>
                  </div>
                </div>
              </div>

              {session.device_id !== currentDeviceId && (
                <button
                  disabled={!!actionLoading}
                  onClick={() => handleDeactivate(session.id)}
                  className="w-10 h-10 rounded-xl bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white transition-all flex items-center justify-center border border-red-500/10"
                >
                  {actionLoading === session.id ? (
                    <RefreshCcw size={14} className="animate-spin" />
                  ) : (
                    <LogOut size={14} />
                  )}
                </button>
              )}

              {session.device_id === currentDeviceId && (
                <div className="w-10 h-10 rounded-xl bg-brand-primary/10 text-brand-primary flex items-center justify-center border border-brand-primary/10 opacity-40">
                   <ShieldCheck size={16} />
                </div>
              )}
            </motion.div>
          ))}
        </AnimatePresence>

        {sessions.length === 0 && !loading && (
          <div className="py-10 text-center opacity-40">
             <Smartphone size={32} className="mx-auto mb-3" />
             <p className="text-[10px] font-black uppercase tracking-[0.3em]">No registered terminals</p>
          </div>
        )}
      </div>

      <div className="p-5 rounded-2xl bg-slate-900/60 border border-white/5 space-y-2">
         <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest italic leading-relaxed">
           <span className="text-brand-primary">Security Tip:</span> Agar aap koi aisa device dekh rahe hain jo aapka nahi hai, toh usey turant deactivate karein aur apna password badlein.
         </p>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { AD_CONFIG } from '../../utils/adConfig';
import { ExternalLink, Info } from 'lucide-react';
import { supabase } from '../../lib/supabase';

interface AdBannerProps {
  slot: keyof typeof AD_CONFIG.slots;
  className?: string;
  isPremium?: boolean;
}

export default function AdBanner({ slot, className = '', isPremium = false }: AdBannerProps) {
  const [showAds, setShowAds] = useState<boolean | null>(null);

  // Fetch global ad config
  useEffect(() => {
    const fetchGlobalAdSetting = async () => {
      try {
        const { data } = await supabase
          .from('admin_settings')
          .select('value')
          .eq('key', 'show_ads')
          .single();

        if (data && (data.value === false || data.value === 'false')) {
          setShowAds(false);
        } else {
          setShowAds(true); 
        }
      } catch (err) {
        // Fallback to local config if offline or table doesn't exist
        setShowAds(AD_CONFIG.enabled);
      }
    };

    fetchGlobalAdSetting();
  }, []);

  // Effect to load AdSense script if needed
  useEffect(() => {
    if (showAds === true && !import.meta.env.DEV) {
      try {
        (window as any).adsbygoogle = (window as any).adsbygoogle || [];
        (window as any).adsbygoogle.push({});
      } catch (e) {
        console.error('AdSense error:', e);
      }
    }
  }, [slot, showAds]);

  if (showAds === null) {
      return (
         <div className={`my-4 animate-pulse bg-slate-100 dark:bg-slate-800 h-[100px] rounded-2xl ${className}`} />
      );
  }

  // Don't show if globally disabled or if user is premium and config says hide
  if (!showAds || (isPremium && !AD_CONFIG.showToPremiumUsers)) {
    return null;
  }

  return (
    <div className={`ad-container my-4 flex flex-col items-center justify-center transition-all ${className}`}>
      <div className="w-full overflow-hidden rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50">
        {import.meta.env.DEV ? (
          /* Development Placeholder / Custom Sponsorship */
          <div className="relative group">
            <div className="absolute top-2 right-2 flex items-center gap-1 bg-white/20 backdrop-blur-md px-2 py-0.5 rounded-full border border-slate-200 dark:border-white/10 z-10">
               <Info size={10} className="text-slate-400" />
               <span className="text-[8px] font-black uppercase text-slate-500 tracking-tighter">Sponsored</span>
            </div>

            {AD_CONFIG.sponsorship.enabled ? (
              <a 
                href={AD_CONFIG.sponsorship.link} 
                target="_blank" 
                rel="noopener noreferrer"
                className="flex items-center gap-4 p-4 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
              >
                <div className="w-12 h-12 rounded-xl overflow-hidden shrink-0 border border-slate-200 dark:border-slate-700 bg-white">
                  <img src={AD_CONFIG.sponsorship.image} alt="Pro" className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] font-black text-kirana-green uppercase tracking-widest mb-1">Order-Do // Boost</p>
                  <h4 className="text-sm font-bold text-slate-800 dark:text-white truncate">{AD_CONFIG.sponsorship.text}</h4>
                </div>
                <ExternalLink size={16} className="text-slate-400 group-hover:text-kirana-green transition-colors" />
              </a>
            ) : (
               <div className="h-[100px] flex items-center justify-center text-slate-300 dark:text-slate-700 font-black uppercase tracking-[0.3em] text-xs">
                  Ad Slot // {slot}
               </div>
            )}
          </div>
        ) : (
          /* Production AdSense Tag */
          <ins
            className="adsbygoogle"
            style={{ display: 'block' }}
            data-ad-client="ca-pub-0000000000000000" // Placeholder Client ID
            data-ad-slot={AD_CONFIG.slots[slot]}
            data-ad-format="auto"
            data-full-width-responsive="true"
          />
        )}
      </div>
      <p className="mt-2 text-[10px] text-slate-400 font-medium italic text-center">
         Ads help us keep Order-Do free for everyone
      </p>
    </div>
  );
}

import { useRef, useMemo, useState, useEffect, Suspense } from 'react';
import { useFrame } from '@react-three/fiber';
import { useGLTF, useAnimations } from '@react-three/drei';
import * as THREE from 'three';
import { useTalkingCharacter } from '../../context/TalkingCharacterContext';

const AVATAR_URL = 'https://models.readyplayer.me/6584288018e69818816827a5.glb?morphTargets=ARKit,Oculus%20Visemes';

function AvatarRemote() {
  const group = useRef<THREE.Group>(null);
  const { nodes, materials, animations } = useGLTF(AVATAR_URL) as any;
  const { actions, names } = useAnimations(animations, group);
  const { isSpeaking } = useTalkingCharacter();

  const headMesh = useMemo(() => {
    let mesh: any = null;
    if (nodes) {
      Object.values(nodes).forEach((node: any) => {
        if (node.type === 'SkinnedMesh' && node.morphTargetDictionary) {
          if (node.name.includes('Head') || node.name.includes('Avatar')) {
            mesh = node;
          }
        }
      });
    }
    return mesh;
  }, [nodes]);

  useEffect(() => {
    if (actions && names.length > 0) {
      const idleName = names.find(n => n.toLowerCase().includes('idle')) || names[0];
      const animationAction = actions[idleName];
      if (animationAction) {
        animationAction.reset().fadeIn(0.5).play();
      }
    }
  }, [actions, names]);

  useFrame((state) => {
    if (group.current) {
        group.current.rotation.y = Math.sin(state.clock.elapsedTime * 0.5) * 0.05;
        group.current.position.y = -1.6 + Math.sin(state.clock.elapsedTime * 2) * 0.02;
    }

    if (headMesh) {
      const dict = headMesh.morphTargetDictionary;
      const influences = headMesh.morphTargetInfluences;
      if (dict && influences) {
        // Eye Blink
        const bl = dict['eyeBlinkLeft'] || dict['EyeBlinkLeft'];
        const br = dict['eyeBlinkRight'] || dict['EyeBlinkRight'];
        const bv = Math.sin(state.clock.elapsedTime * 5) > 0.98 ? 1 : 0;
        if (bl !== undefined) influences[bl] = THREE.MathUtils.lerp(influences[bl], bv, 0.2);
        if (br !== undefined) influences[br] = THREE.MathUtils.lerp(influences[br], bv, 0.2);

        // Lip Sync / Mouth Open
        const mo = dict['mouthOpen'] || dict['MouthOpen'] || dict['viseme_aa'] || dict['jawOpen'];
        const si = isSpeaking ? Math.abs(Math.sin(state.clock.elapsedTime * 15)) * 0.8 : 0;
        if (mo !== undefined) influences[mo] = THREE.MathUtils.lerp(influences[mo], si, 0.3);
      }
    }
  });

  return (
    <group ref={group} dispose={null} position={[0, -1.6, 0]} scale={1}>
      <primitive object={nodes.Hips} />
      {Object.values(nodes).map((node: any, i) => (
        node.type === 'SkinnedMesh' && (
          <skinnedMesh
            key={i}
            geometry={node.geometry}
            material={materials[node.material.name]}
            skeleton={node.skeleton}
            morphTargetDictionary={node.morphTargetDictionary}
            morphTargetInfluences={node.morphTargetInfluences}
            castShadow
            receiveShadow
          />
        )
      ))}
    </group>
  );
}

function AvatarFallback() {
  const headRef = useRef<THREE.Group>(null);
  const mouthRef = useRef<THREE.Mesh>(null);
  const bodyRef = useRef<THREE.Group>(null);
  const { isSpeaking } = useTalkingCharacter();

  useFrame((state) => {
    const time = state.clock.elapsedTime;
    
    if (headRef.current) {
        headRef.current.rotation.y = Math.sin(time * 0.5) * 0.1;
        headRef.current.rotation.x = Math.sin(time * 0.3) * 0.05;
    }

    if (bodyRef.current) {
        bodyRef.current.position.y = Math.sin(time * 2) * 0.02 - 0.4;
        bodyRef.current.rotation.z = Math.sin(time * 1.5) * 0.02;
    }
    
    if (mouthRef.current && isSpeaking) {
        const s = Math.abs(Math.sin(time * 15)) * 0.8 + 0.2;
        mouthRef.current.scale.y = s;
    } else if (mouthRef.current) {
        mouthRef.current.scale.y = THREE.MathUtils.lerp(mouthRef.current.scale.y, 0.1, 0.1);
    }
  });

  return (
    <group position={[0, -0.4, 0]}>
      {/* Body / Torso (Female profile) */}
      <group ref={bodyRef}>
        <mesh position={[0, -0.2, 0]} castShadow>
          <capsuleGeometry args={[0.25, 0.5, 8, 16]} />
          <meshStandardMaterial color="#334155" metalness={0.1} roughness={0.7} />
        </mesh>
        {/* Arms */}
        <mesh position={[-0.35, 0, 0]} rotation={[0, 0, 0.2]}>
          <capsuleGeometry args={[0.06, 0.4, 4, 8]} />
          <meshStandardMaterial color="#fcd34d" />
        </mesh>
        <mesh position={[0.35, 0, 0]} rotation={[0, 0, -0.2]}>
          <capsuleGeometry args={[0.06, 0.4, 4, 8]} />
          <meshStandardMaterial color="#fcd34d" />
        </mesh>
      </group>
      
      {/* Head */}
      <group ref={headRef} position={[0, 0.35, 0]}>
        <mesh castShadow>
          <sphereGeometry args={[0.28, 32, 32]} />
          <meshStandardMaterial color="#fcd34d" metalness={0.05} roughness={0.9} />
          
          {/* Hair (Feminine style) */}
          <mesh position={[0, 0.1, -0.05]} rotation={[0.4, 0, 0]}>
              <sphereGeometry args={[0.3, 32, 16, 0, Math.PI * 2, 0, Math.PI * 0.6]} />
              <meshStandardMaterial color="#1e293b" />
          </mesh>
          <mesh position={[0.2, -0.1, -0.1]} rotation={[0, 0, -0.2]}>
              <capsuleGeometry args={[0.1, 0.3, 4, 8]} />
              <meshStandardMaterial color="#1e293b" />
          </mesh>
          <mesh position={[-0.2, -0.1, -0.1]} rotation={[0, 0, 0.2]}>
              <capsuleGeometry args={[0.1, 0.3, 4, 8]} />
              <meshStandardMaterial color="#1e293b" />
          </mesh>
          
          {/* Eyes */}
          <mesh position={[-0.1, 0.05, 0.22]}>
              <sphereGeometry args={[0.035, 16, 16]} />
              <meshStandardMaterial color="#000" />
          </mesh>
          <mesh position={[0.1, 0.05, 0.22]}>
              <sphereGeometry args={[0.035, 16, 16]} />
              <meshStandardMaterial color="#000" />
          </mesh>
          
          {/* Mouth */}
          <mesh ref={mouthRef} position={[0, -0.1, 0.25]}>
              <boxGeometry args={[0.1, 0.06, 0.03]} />
              <meshStandardMaterial color="#be123c" />
          </mesh>
        </mesh>
      </group>
    </group>
  );
}

export default function Avatar3D() {
    const [loadError, setLoadError] = useState(false);
    const [hasInternet, setHasInternet] = useState(true);

    useEffect(() => {
        const checkInternet = async () => {
            try {
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), 3000);
                await fetch('https://models.readyplayer.me/ready.png', { mode: 'no-cors', signal: controller.signal });
                clearTimeout(timeoutId);
                setHasInternet(true);
            } catch (e) {
                setHasInternet(false);
                setLoadError(true);
            }
        };
        checkInternet();
    }, []);

    if (loadError || !hasInternet) return <AvatarFallback />;

    return (
        <Suspense fallback={<AvatarFallback />}>
            <AvatarRemote />
        </Suspense>
    );
}

import { Component, type ErrorInfo, type ReactNode } from 'react';

interface Props {
  children: ReactNode;
  fallback: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
}

interface State {
  hasError: boolean;
}

export default class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(_: Error): State {
    return { hasError: true };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
    if (this.props.onError) {
      this.props.onError(error, errorInfo);
    }
  }

  public render() {
    if (this.state.hasError) {
      return this.props.fallback;
    }

    return this.props.children;
  }
}

import { useRef, useEffect, useCallback } from 'react';

interface SecureCanvasProps {
  content?: string | string[]; // Array of strings for multiline
  image?: string;
  width?: number;
  height?: number;
  className?: string;
  fontSize?: number;
  tagline?: string;
  textAlign?: 'left' | 'center' | 'right';
  shopName?: string;
}

export default function SecureCanvas({ 
  content, 
  image, 
  width = 300, 
  height = 200, 
  className = "", 
  fontSize = 18,
  tagline = "Order-Do // Private",
  textAlign = 'left',
  shopName = "Order-Do Cloud"
}: SecureCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const applySecurityLayers = useCallback((ctx: CanvasRenderingContext2D) => {
    // 3. PROMINENT FORENSIC WATERMARK (Diagonal & Visible)
    ctx.save();
    ctx.globalCompositeOperation = 'source-over';
    ctx.fillStyle = 'rgba(0, 0, 0, 0.08)'; // More visible
    ctx.font = 'black 14px "Outfit", sans-serif';
    const watermarkText = `PROPERTY OF ${shopName.toUpperCase()} // FORENSIC LOG ACTIVE`;

    ctx.translate(width / 2, height / 2);
    ctx.rotate(-Math.PI / 4); // 45 degree angle

    // Draw multiple lines if it's a large canvas (like image)
    if (image) {
        ctx.fillStyle = 'rgba(255, 255, 255, 0.15)'; // White watermark on photos
        for(let i = -3; i <= 3; i++) {
            ctx.fillText(watermarkText, -width, i * 40);
        }
    } else {
        ctx.fillText(watermarkText, -width/1.5, 0);
    }
    ctx.restore();

    // 4. STEGANOGRAPHIC NOISE WATERMARK (Subtle)
    ctx.save();
    ctx.fillStyle = 'rgba(0, 0, 0, 0.015)';
    ctx.font = 'bold 8px monospace';
    const hiddenText = `${tagline} • ${new Date().toLocaleTimeString()} • ${Math.random().toString(36).substring(7)}`;

    for (let y = 0; y < height; y += 100) {
      for (let x = 0; x < width; x += 180) {
        ctx.fillText(hiddenText, x, y);
      }
    }
    ctx.restore();

    // 4. STATIC NOISE OVERLAY (Simpler, faster)
    ctx.save();
    ctx.globalAlpha = 0.03;
    for (let i = 0; i < 500; i++) {
        ctx.fillStyle = Math.random() > 0.5 ? '#ffffff' : '#000000';
        ctx.fillRect(Math.random() * width, Math.random() * height, 1, 1);
    }
    ctx.restore();
  }, [width, height, tagline]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    // Clear and draw background
    const isTransparent = className.includes('bg-transparent');
    const isDark = document.documentElement.classList.contains('dark');

    if (!isTransparent) {
      ctx.fillStyle = isDark ? '#1e293b' : '#ffffff';
      ctx.fillRect(0, 0, width, height);
    } else {
      ctx.clearRect(0, 0, width, height);
    }

    if (image) {
      const img = new Image();
      img.src = image;
      img.onload = () => {
        ctx.drawImage(img, 0, 0, width, height);
        applySecurityLayers(ctx);
      };
    } else {
      // Dynamic text color based on theme and background
      ctx.fillStyle = isTransparent 
        ? (isDark ? '#e2e8f0' : '#0f172a') 
        : (isDark ? '#64748b' : '#0f172a');

      ctx.font = `bold ${fontSize}px "Outfit", "Inter", sans-serif`;
      ctx.textBaseline = 'top';
      ctx.textAlign = textAlign;

      const xPos = textAlign === 'center' ? width / 2 : textAlign === 'right' ? width : 0;

      if (Array.isArray(content)) {
        content.forEach((line, idx) => {
          ctx.fillText(line, xPos, 0 + idx * (fontSize + 4));
        });
      } else if (content) {
        ctx.fillText(content, xPos, 0);
      }

      applySecurityLayers(ctx);
    }
  }, [content, image, width, height, fontSize, textAlign, applySecurityLayers]);

  useEffect(() => {
    draw();
  }, [draw]);

  const hasBorder = !className.includes('border-none');

  return (
    <div className={`secure-canvas-wrapper relative overflow-hidden select-none ${hasBorder ? 'rounded-2xl border-2 border-slate-100 dark:border-slate-800' : ''} ${className}`}>
      <canvas 
        ref={canvasRef} 
        width={width} 
        height={height} 
        className="block max-w-full h-auto pointer-events-none"
        aria-label="Secure content rendered on canvas"
      />
      {/* Noise animation layer (from CSS) */}
      <div className="absolute inset-0 pointer-events-none z-10 opacity-[0.05] mix-blend-overlay secure-content" />
    </div>
  );
}

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle, Home, Sparkles, Receipt, Star, Shield } from 'lucide-react';
import { useLanguage } from '../../context/LanguageContext';
import { supabase } from '../../lib/supabase';
import { toast } from 'sonner';
import Confetti from './Confetti';
import GlassCard from './GlassCard';
import Button from './Button';
import haptics from '../../utils/haptics';

interface SuccessModalProps {
  isOpen: boolean;
  onClose: () => void;
  shopId?: string;
  shopUUID?: string;
  orderId?: string;
  orderSummary?: {
    customerName: string;
    totalAmount: number;
    itemsCount: number;
  };
  onShareReceipt?: () => void;
  orderStatus?: string; // e.g. 'pending', 'accepted', 'preparing', 'ready', 'completed'
  feedbackEnabled?: boolean;
}

export default function SuccessModal({ 
  isOpen, 
  onClose, 
  shopUUID,
  orderId,
  orderSummary, 
  onShareReceipt,
  orderStatus = 'pending',
  feedbackEnabled = true
}: SuccessModalProps) {
  const { t, language } = useLanguage();
  const [rating, setRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [comment, setComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedbackSent, setFeedbackSent] = useState(false);

  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'pending': return language === 'hi' ? 'दुकानदार का इंतज़ार' : 'Waiting for shop';
      case 'accepted': return language === 'hi' ? 'स्वीकार किया गया' : 'Order Accepted';
      case 'preparing': return language === 'hi' ? 'बन रहा है' : 'Preparing Order';
      case 'ready': return language === 'hi' ? 'तैयार है!' : 'Ready for Pickup';
      case 'completed': return language === 'hi' ? 'मौज लो!' : 'Enjoy your meal!';
      default: return status.toUpperCase();
    }
  };

  const statusProgress = {
    'pending': 20,
    'accepted': 40,
    'preparing': 60,
    'ready': 80,
    'completed': 100
  };

  const handleRatingSubmit = async () => {
    if (rating === 0 || !shopUUID) return;
    setIsSubmitting(true);
    try {
      const { error } = await supabase.from('order_feedback').insert({
        shop_id: shopUUID,
        order_id: orderId || `temp-${Date.now()}`,
        stars: rating,
        comment: comment.trim() || null
      });

      if (error) throw error;
      setFeedbackSent(true);
      toast.success(language === 'hi' ? 'फीडबैक के लिए धन्यवाद!' : 'Thanks for your feedback!');
      haptics.success();
    } catch (err) {
      toast.error('Failed to send feedback');
    } finally {
      setIsSubmitting(false);
    }
  };

  const showFeedback = feedbackEnabled && (orderStatus === 'ready' || orderStatus === 'completed');

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0"
            onClick={onClose}
          />

          <motion.div
            initial={{ scale: 0.9, opacity: 0, y: 40 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.9, opacity: 0, y: 40 }}
            className="relative w-full max-w-sm overflow-hidden max-h-[90vh] overflow-y-auto no-scrollbar"
          >
            {orderStatus === 'completed' && <Confetti />}

            <GlassCard intensity="high" className="border-white/20 dark:border-white/10 shadow-[0_0_100px_rgba(0,0,0,0.5)]">
              <div className="p-8 flex flex-col items-center text-center relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-brand-primary opacity-10 blur-[50px] rounded-full" />
                <div className="absolute bottom-0 left-0 w-32 h-32 bg-brand-secondary opacity-10 blur-[50px] rounded-full" />

                <div className="w-full mb-8 space-y-3">
                  <div className="flex justify-between items-center px-1">
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-brand-primary animate-pulse">
                      {getStatusLabel(orderStatus)}
                    </span>
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Live Tracker</span>
                  </div>
                  <div className="h-2 w-full bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden p-[1px]">
                    <motion.div 
                      initial={{ width: '0%' }}
                      animate={{ width: `${(statusProgress as any)[orderStatus] || 20}%` }}
                      className="h-full bg-gradient-to-r from-brand-primary to-brand-secondary rounded-full shadow-glow-green"
                    />
                  </div>
                </div>

                <motion.div
                  initial={{ scale: 0, rotate: -45 }}
                  animate={{ scale: [0, 1.3, 1], rotate: 0 }}
                  transition={{ type: "spring", stiffness: 260, damping: 20, delay: 0.2 }}
                  className="w-20 h-20 bg-brand-primary/10 rounded-[2rem] flex items-center justify-center mb-6 border border-brand-primary/20 shadow-glow-green/20 relative"
                >
                  <CheckCircle size={44} className="text-brand-primary" />
                </motion.div>

                <h2 className="text-2xl font-black text-slate-900 dark:text-white leading-tight uppercase italic tracking-tighter mb-4">
                  {t('customer.orderSuccessTitle')}
                </h2>

                {/* Verification ID Section */}
                {orderId && (
                  <div className="w-full mb-6 p-4 bg-slate-100 dark:bg-slate-900/60 rounded-2xl border-2 border-dashed border-slate-300 dark:border-slate-700/50 relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-1">
                       <Shield size={10} className="text-brand-primary opacity-30" />
                    </div>
                    <p className="text-[9px] font-black uppercase tracking-widest text-slate-400 mb-1">Digital Verification ID</p>
                    <div className="flex items-center justify-center gap-2">
                      <span className="text-xl font-mono font-black text-brand-primary tracking-widest uppercase italic">
                        ORD-{orderId.slice(0, 4).toUpperCase()}
                      </span>
                    </div>
                    <p className="text-[8px] font-bold text-slate-500 mt-1 italic">Show this to shopkeeper for verification</p>
                  </div>
                )}

                {/* Feedback Section */}
                {showFeedback && !feedbackSent && (
                  <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="w-full bg-white/40 dark:bg-slate-900/40 p-5 rounded-[2rem] border border-white/20 mb-6">
                    <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4">How was your experience?</p>
                    <div className="flex justify-center gap-2 mb-4">
                      {[1, 2, 3, 4, 5].map((star) => (
                        <button
                          key={star}
                          onMouseEnter={() => setHoverRating(star)}
                          onMouseLeave={() => setHoverRating(0)}
                          onClick={() => { setRating(star); haptics.light(); }}
                          className="transition-transform active:scale-90"
                        >
                          <Star 
                            size={28} 
                            className={`transition-colors ${
                              star <= (hoverRating || rating) 
                                ? 'fill-yellow-400 text-yellow-400' 
                                : 'text-slate-300 dark:text-slate-700'
                            }`} 
                          />
                        </button>
                      ))}
                    </div>
                    {rating > 0 && (
                      <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="space-y-3">
                        <textarea
                          placeholder={language === 'hi' ? 'कुछ कहना चाहेंगे?' : 'Any comments?'}
                          value={comment}
                          onChange={(e) => setComment(e.target.value)}
                          className="w-full bg-white/60 dark:bg-slate-800/60 border border-white/20 rounded-xl p-3 text-sm focus:ring-2 ring-brand-primary outline-none transition-all resize-none h-20"
                        />
                        <Button 
                          onClick={handleRatingSubmit} 
                          isLoading={isSubmitting} 
                          variant="primary" 
                          className="w-full h-10 !rounded-xl text-xs uppercase font-black"
                        >
                          Submit Feedback
                        </Button>
                      </motion.div>
                    )}
                  </motion.div>
                )}

                {feedbackSent && (
                  <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="mb-6 p-4 bg-green-500/10 rounded-2xl border border-green-500/20 text-green-500 text-xs font-bold italic">
                    <Sparkles size={16} className="inline mr-2" />
                    Thank you for the magic feedback!
                  </motion.div>
                )}

                {orderSummary && !showFeedback && (
                  <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.6 }} className="w-full p-6 rounded-[2rem] bg-white/40 dark:bg-slate-950/40 border border-white/20 dark:border-white/5 shadow-inner space-y-4 mb-6">
                    <div className="flex justify-between items-center">
                       <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Inventory</span>
                       <span className="text-xs font-black text-slate-900 dark:text-white uppercase italic">{orderSummary.itemsCount} {t('report.items')}</span>
                    </div>

                    <div className="pt-4 border-t border-slate-200/50 dark:border-slate-800/50 flex justify-between items-center group">
                       <span className="text-[10px] font-black uppercase tracking-widest text-brand-primary">Settlement</span>
                       <span className="text-xl font-black text-brand-primary tracking-tighter italic">₹{orderSummary.totalAmount}</span>
                    </div>
                  </motion.div>
                )}

                <div className="w-full space-y-4">
                  {onShareReceipt && (
                    <Button onClick={onShareReceipt} variant="ghost" className="w-full h-14 !rounded-xl text-sm font-black uppercase text-brand-primary tracking-widest border border-brand-primary/20">
                      <Receipt size={18} className="mr-3" />
                      Share Receipt
                    </Button>
                  )}
                  <Button onClick={onClose} variant="primary" className="w-full h-14 !rounded-xl shadow-glow-green text-sm font-black uppercase italic tracking-widest text-white">
                    <Home size={18} className="mr-3" />
                    {t('common.home')}
                  </Button>
                </div>
              </div>
            </GlassCard>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

import { useRef, useMemo, useEffect, Suspense } from 'react';
import { useFrame } from '@react-three/fiber';
import { useGLTF, useAnimations, ContactShadows, PerspectiveCamera } from '@react-three/drei';
import * as THREE from 'three';
import { useTalkingCharacter } from '../../context/TalkingCharacterContext';

// High-quality Indian female character (Ready Player Me)
// Features: Salwar Kameez, Ponytail, Expressive eyes
const MODEL_URL = 'https://models.readyplayer.me/6584288018e69818816827a5.glb?morphTargets=ARKit,Oculus%20Visemes';

function InstructorModel() {
  const group = useRef<THREE.Group>(null);
  const gltf = useGLTF(MODEL_URL, true) as any;
  const { nodes, materials, animations } = gltf || {};
  const { actions, names } = useAnimations(animations || [], group);
  const { isSpeaking, action } = useTalkingCharacter();

  // Optimized Resource Disposal
  useEffect(() => {
    return () => {
      if (group.current) {
        group.current.traverse((obj: any) => {
          if (obj.isMesh) {
            obj.geometry.dispose();
            if (Array.isArray(obj.material)) obj.material.forEach((m: any) => m.dispose());
            else obj.material.dispose();
          }
        });
      }
    };
  }, []);

  const headMesh = useMemo(() => {
    if (!nodes) return null;
    let mesh: any = null;
    Object.values(nodes).forEach((node: any) => {
      if (node.type === 'SkinnedMesh' && node.morphTargetDictionary) {
        if (node.name.toLowerCase().includes('head') || node.name.toLowerCase().includes('avatar')) {
          mesh = node;
        }
      }
    });
    return mesh;
  }, [nodes]);

  useEffect(() => {
    if (actions && names && names.length > 0) {
      const nextAction = names.find(n => n.toLowerCase().includes(action)) || 
                         names.find(n => n.toLowerCase().includes('idle')) || 
                         names[0];
      const animationAction = actions[nextAction];
      if (animationAction) {
        Object.values(actions).forEach(a => a?.fadeOut(0.3));
        animationAction.reset().fadeIn(0.3).play();
      }
    }
  }, [actions, names, action]);

  useFrame((state) => {
    const time = state.clock.elapsedTime;
    if (group.current) {
      group.current.position.y = -1.5 + Math.sin(time * 1.5) * 0.03;
      group.current.rotation.y = Math.sin(time * 0.5) * 0.05 + state.mouse.x * 0.1;
      group.current.rotation.x = -state.mouse.y * 0.05;
      
      // Simple LOD: Check distance to camera
      const dist = state.camera.position.distanceTo(group.current.position);
      group.current.visible = dist < 10; // Hide if too far
    }

    if (headMesh && headMesh.morphTargetDictionary && headMesh.morphTargetInfluences) {
      const dict = headMesh.morphTargetDictionary;
      const influences = headMesh.morphTargetInfluences;
      const blinkVal = Math.sin(time * 4) > 0.98 ? 1 : 0;
      const mouthVal = isSpeaking ? Math.abs(Math.sin(time * 18)) * 0.7 + (Math.random() * 0.2) : 0;
      
      const eyeL = dict['eyeBlinkLeft'] || dict['EyeBlinkLeft'];
      const eyeR = dict['eyeBlinkRight'] || dict['EyeBlinkRight'];
      const jaw = dict['jawOpen'] || dict['mouthOpen'];

      if (eyeL !== undefined) influences[eyeL] = THREE.MathUtils.lerp(influences[eyeL], blinkVal, 0.2);
      if (eyeR !== undefined) influences[eyeR] = THREE.MathUtils.lerp(influences[eyeR], blinkVal, 0.2);
      if (jaw !== undefined) influences[jaw] = THREE.MathUtils.lerp(influences[jaw], mouthVal, 0.3);
    }
  });

  if (!nodes || !materials) return <ProfessionalFallback isSpeaking={isSpeaking} />;

  return (
    <group ref={group} dispose={null} position={[0, -1.5, 0]} scale={1.1}>
      <primitive object={nodes.Hips} />
      {Object.values(nodes).map((node: any, i) => (
        node.type === 'SkinnedMesh' && (
          <skinnedMesh
            key={i}
            geometry={node.geometry}
            material={materials[node.material.name]}
            skeleton={node.skeleton}
            morphTargetDictionary={node.morphTargetDictionary}
            morphTargetInfluences={node.morphTargetInfluences}
            castShadow
            receiveShadow
          />
        )
      ))}
    </group>
  );
}

function ProfessionalFallback({ isSpeaking }: { isSpeaking: boolean }) {
  const group = useRef<THREE.Group>(null);
  const head = useRef<THREE.Mesh>(null);
  const mouth = useRef<THREE.Mesh>(null);

  useEffect(() => {
    return () => {
      if (group.current) {
        group.current.traverse((obj: any) => {
          if (obj.isMesh) {
            obj.geometry.dispose();
            if (Array.isArray(obj.material)) obj.material.forEach((m: any) => m.dispose());
            else obj.material.dispose();
          }
        });
      }
    };
  }, []);

  useFrame((state) => {
    const t = state.clock.elapsedTime;
    if (group.current) group.current.position.y = -1.2 + Math.sin(t * 2) * 0.05;
    if (mouth.current && isSpeaking) mouth.current.scale.y = 0.2 + Math.abs(Math.sin(t * 15)) * 0.8;
    if (head.current) head.current.rotation.y = state.mouse.x * 0.2;
  });

  return (
    <group ref={group}>
      <mesh position={[0, 0, 0]} castShadow>
        <capsuleGeometry args={[0.22, 0.5, 8, 16]} />
        <meshStandardMaterial color="#3b82f6" metalness={0.4} roughness={0.3} />
      </mesh>
      <mesh ref={head} position={[0, 0.5, 0]} castShadow>
        <sphereGeometry args={[0.16, 16, 16]} />
        <meshStandardMaterial color="#ffdbac" metalness={0.1} roughness={0.8} />
        <mesh position={[-0.05, 0.03, 0.12]}>
          <sphereGeometry args={[0.02, 4, 4]} />
          <meshStandardMaterial color="#000" />
        </mesh>
        <mesh position={[0.05, 0.03, 0.12]}>
          <sphereGeometry args={[0.02, 4, 4]} />
          <meshStandardMaterial color="#000" />
        </mesh>
        <mesh ref={mouth} position={[0, -0.05, 0.14]}>
          <boxGeometry args={[0.04, 0.01, 0.01]} />
          <meshStandardMaterial color="#911" />
        </mesh>
      </mesh>
      <mesh position={[0, 0.55, -0.08]} rotation={[0.4, 0, 0]}>
        <sphereGeometry args={[0.17, 16, 8]} />
        <meshStandardMaterial color="#111" />
      </mesh>
      <mesh position={[0, 0.35, -0.2]}>
        <capsuleGeometry args={[0.04, 0.3, 4, 4]} />
        <meshStandardMaterial color="#111" />
      </mesh>
    </group>
  );
}

export default function VirtualInstructor() {
  // Global Dispose management
  useEffect(() => {
    return () => {
      THREE.Cache.clear();
    };
  }, []);

  return (
    <Suspense fallback={<ProfessionalFallback isSpeaking={false} />}>
      <PerspectiveCamera makeDefault position={[0, 0.3, 1.8]} fov={35} />
      <ambientLight intensity={1.5} />
      <spotLight position={[5, 10, 5]} angle={0.15} penumbra={1} intensity={2} castShadow />
      <directionalLight position={[-2, 5, 2]} intensity={1} />
      
      <InstructorModel />
      
      <ContactShadows resolution={1024} scale={6} blur={2.5} opacity={0.4} far={10} color="#000000" />
    </Suspense>
  );
}

