import React, { createContext, useContext, useEffect, useState, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { useAuth } from './AuthContext';
import { isExpired } from '../utils/dateUtils';

interface Subscription {
  status: 'active' | 'expired' | 'pending';
  expiry_date: string | null;
  confirmed_at: string | null;
  plan: {
    id: number;
    name: string;
    features: Record<string, boolean>;
  };
}

interface SubscriptionContextType {
  subscription: Subscription | null;
  loading: boolean;
  globalFree: boolean;
  hasFeature: (featureId: string) => boolean;
  refreshSubscription: () => Promise<void>;
}

const SubscriptionContext = createContext<SubscriptionContextType>({
  subscription: null,
  loading: true,
  globalFree: false,
  hasFeature: () => false,
  refreshSubscription: async () => {},
});

export const SubscriptionProvider = ({ children }: { children: React.ReactNode }) => {
  const { user, isAdmin } = useAuth();
  const [subscription, setSubscription] = useState<Subscription | null>(null);
  const [loading, setLoading] = useState(true);
  const [globalFree, setGlobalFree] = useState(false);
  const subscriptionRef = useRef<Subscription | null>(null);

  const fetchSubscription = async () => {
    if (!user) {
      setSubscription(null);
      setLoading(false);
      return;
    }

    try {
      // 1. Validate UUID format to prevent database crash
      const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
      if (!uuidRegex.test(user.id)) {
        setSubscription(null);
        setLoading(false);
        return;
      }

      // 2. Fetch Global Settings
      const { data: settings } = await supabase
        .from('admin_settings')
        .select('value')
        .eq('key', 'global_free_toggle')
        .maybeSingle();

      setGlobalFree(settings?.value === true || settings?.value === 'true');

      // 3. Fetch Shop Subscription and Server Time
      const [subResult, timeResult] = await Promise.all([
        supabase
          .from('subscriptions')
          .select(`
            status,
            expiry_date,
            plan:plans ( id, name, features )
          `)
          .eq('shop_id', user.id)
          .maybeSingle(),
        supabase.rpc('get_server_time')
      ]);

      const subData = subResult.data;
      const serverNow = timeResult.data ? new Date(timeResult.data) : new Date();

      if (subData && (subData.status === 'active' || subData.status === 'expired')) {
        // Double check status based on server time
        const actualStatus = (subData.status === 'active' && isExpired(subData.expiry_date, serverNow)) 
          ? 'expired' 
          : subData.status;

        setSubscription({ ...subData, status: actualStatus } as any);
      } else {
        // Check for a pending payment request to show "Selected Plan"
        const { data: pendingPayment } = await supabase
          .from('payments')
          .select('plan:plans(id, name, features)')
          .eq('shop_id', user.id)
          .eq('status', 'pending')
          .order('created_at', { ascending: false })
          .limit(1)
          .maybeSingle();

        if (pendingPayment) {
          setSubscription({
            status: 'pending',
            expiry_date: null,
            confirmed_at: null,
            plan: pendingPayment.plan as any
          });
        } else {
          setSubscription(subData as any || null);
        }
      }

      // 4. Fetch Activation Timestamp for active subscriptions from payment_history
      if (subData && subData.status === 'active') {
        const { data: activatedRecord } = await supabase
          .from('payment_history')
          .select('confirmed_at')
          .eq('shop_id', user.id)
          .eq('status', 'confirmed')
          .order('confirmed_at', { ascending: false })
          .limit(1)
          .maybeSingle();

        if (activatedRecord) {
          setSubscription(prev => prev ? { ...prev, confirmed_at: activatedRecord.confirmed_at } : null);
        }
      }
    } catch (err) {
      console.error('Error fetching subscription:', err);
    } finally {
      setLoading(false);
    }
  };

  // TC-015: Keep ref in sync with state for heartbeat access
  useEffect(() => {
    subscriptionRef.current = subscription;
  }, [subscription]);

  useEffect(() => {
    fetchSubscription();

    if (!user) return;

    // TC-015 FIX: Heartbeat uses ref to avoid stale closure
    // Always re-fetch from server to get fresh expiry state
    const heartbeat = setInterval(() => {
      const current = subscriptionRef.current;
      if (current?.expiry_date && isExpired(current.expiry_date)) {
        console.log('[SubscriptionContext] Heartbeat detected expiration');
        fetchSubscription(); // Refresh state to lock UI
      }
    }, 60000);

    // Listen for realtime updates to this shop's subscription or payments
    const channel = supabase.channel(`shop-sub-${user.id}`)
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'subscriptions',
        filter: `shop_id=eq.${user.id}`
      }, () => {
        console.log('[SubscriptionContext] Realtime Update detected (subscriptions)');
        fetchSubscription();
      })
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'payment_history',
        filter: `shop_id=eq.${user.id}`
      }, () => {
        console.log('[SubscriptionContext] Realtime Update detected (payment_history)');
        fetchSubscription();
      })
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'payments',
        filter: `shop_id=eq.${user.id}`
      }, () => {
        console.log('[SubscriptionContext] Realtime Update detected (payments pool)');
        fetchSubscription();
      })
      .subscribe();

    return () => {
      clearInterval(heartbeat);
      supabase.removeChannel(channel);
    };
  }, [user]);

  const hasFeature = (featureId: string) => {
    // Admin always has all features
    if (isAdmin) return true;

    // Global Free Toggle
    if (globalFree) return true;

    // Check Subscription
    if (!subscription || subscription.status !== 'active') return false;

    // Check if expiry date has passed
    if (isExpired(subscription.expiry_date)) {
      return false;
    }

    // Check plan features
    return subscription.plan.features[featureId] === true;
  };

  return (
    <SubscriptionContext.Provider value={{ 
      subscription, 
      loading, 
      globalFree,
      hasFeature, 
      refreshSubscription: fetchSubscription 
    }}>
      {children}
    </SubscriptionContext.Provider>
  );
};

export const useSubscription = () => useContext(SubscriptionContext);

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../../lib/supabase';
import { 
  Users, 
  CreditCard, 
  ArrowUpRight, 
  ShieldCheck,
  Zap,
  Settings,
  TrendingUp as TrendingUpIcon,
  Crown,
  AlertCircle,
  Clock,
  LayoutDashboard,
  Activity as ActivityIcon,
  Globe
} from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer
} from 'recharts';
import { motion, AnimatePresence } from 'framer-motion';
import { useLanguage } from '../../context/LanguageContext';
import GlassCard from '../../components/ui/GlassCard';
import Button from '../../components/ui/Button';

interface Activity {
  id: string;
  shop_name: string;
  amount: number;
  confirmed_at: string;
  plan_name: string;
}

export default function AdminDashboard() {
  useLanguage();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalShops: 0,
    activeSubs: 0,
    pendingPayments: 0,
    revenue: 0
  });
  const [recentActivity, setRecentActivity] = useState<Activity[]>([]);
  const [chartData, setChartData] = useState<any[]>([]);
  const [topShops, setTopShops] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [networkPressure, setNetworkPressure] = useState(15);
  const [activityNodes, setActivityNodes] = useState<number[]>([]);

  const fetchStats = async () => {
    try {
      const [shopsRes, subsRes, paymentsRes, confirmedRes] = await Promise.all([
        supabase.from('shops_profile').select('*', { count: 'exact', head: true }),
        supabase.from('subscriptions').select('*', { count: 'exact', head: true }).eq('status', 'active'),
        supabase.from('payments').select('shop_id').eq('status', 'pending'),
        supabase.from('payment_history').select('*').eq('status', 'confirmed')
      ]);

      const { count: manualPendingCount } = await supabase.from('subscriptions').select('*', { count: 'exact', head: true }).eq('status', 'pending');

      const paymentShopIds = new Set(paymentsRes.data?.map(p => p.shop_id) || []);
      const totalPending = paymentShopIds.size + (manualPendingCount || 0);

      const totalRevenue = confirmedRes.data?.reduce((sum, p) => sum + Number(p.amount), 0) || 0;

      setStats({
        totalShops: shopsRes.count || 0,
        activeSubs: subsRes.count || 0,
        pendingPayments: totalPending,
        revenue: totalRevenue
      });

      const last7Days = [...Array(7)].map((_, i) => {
        const d = new Date();
        d.setDate(d.getDate() - i);
        return d.toISOString().split('T')[0];
      }).reverse();

      const dailyRevenue = last7Days.map(date => {
        const revenue = confirmedRes.data
          ?.filter(p => p.confirmed_at && p.confirmed_at.split('T')[0] === date)
          .reduce((sum, p) => sum + Number(p.amount || 0), 0) || 0;
        return {
          date: new Date(date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }),
          revenue
        };
      });
      setChartData(dailyRevenue);

      const shopCounts: Record<string, { name: string, count: number, revenue: number }> = {};
      const { data: shopNames } = await supabase.from('shops_profile').select('id, shop_name');
      const nameMap = Object.fromEntries(shopNames?.map(s => [s.id, s.shop_name]) || []);

      confirmedRes.data?.forEach(p => {
        if (!shopCounts[p.shop_id]) {
          shopCounts[p.shop_id] = { name: nameMap[p.shop_id] || 'Unknown', count: 0, revenue: 0 };
        }
        shopCounts[p.shop_id].count += 1;
        shopCounts[p.shop_id].revenue += Number(p.amount);
      });

      const leaderBoard = Object.values(shopCounts)
        .sort((a, b) => b.revenue - a.revenue)
        .slice(0, 5);
      setTopShops(leaderBoard);

      const { data: activityData } = await supabase
        .from('payment_history')
        .select(`
          id,
          amount,
          confirmed_at,
          shops_profile(shop_name),
          plans(name)
        `)
        .order('confirmed_at', { ascending: false })
        .limit(5);

      if (activityData) {
        setRecentActivity(activityData.map((a: any) => {
          const profile = Array.isArray(a.shops_profile) ? a.shops_profile[0] : a.shops_profile;
          const plan = Array.isArray(a.plans) ? a.plans[0] : a.plans;

          return {
            id: a.id,
            shop_name: profile?.shop_name || 'Unknown Shop',
            amount: a.amount || 0,
            confirmed_at: a.confirmed_at,
            plan_name: plan?.name || 'Standard Plan'
          };
        }));
      }

      // Fetch global pending orders for pressure metric
      const { count: pendingCount } = await supabase
        .from('pending_orders')
        .select('*', { count: 'exact', head: true });

      setNetworkPressure(Math.min(100, (pendingCount || 0) * 10 + 15));

    } catch (err) {
      console.error('Stats Update Error:', err);
    } finally {
      setLoading(false);
    }
  };

  // Generate random activity nodes for the heatmap
  useEffect(() => {
    const nodes = Array.from({ length: 48 }, () => Math.floor(Math.random() * 100));
    setActivityNodes(nodes);

    const interval = setInterval(() => {
      setActivityNodes(prev => prev.map(val => 
        Math.max(0, Math.min(100, val + (Math.random() * 30 - 15)))
      ));
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    fetchStats();

    const channels = supabase.channel('admin-dashboard')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'payments' }, () => fetchStats())
      .on('postgres_changes', { event: '*', schema: 'public', table: 'subscriptions' }, () => fetchStats())
      .on('postgres_changes', { event: '*', schema: 'public', table: 'shops_profile' }, () => fetchStats())
