        {/* Top Performing Shops (Leaderboard) */}
        <div>
           <GlassCard intensity="medium" className="p-10 border-white/40 dark:border-white/10 flex flex-col h-full overflow-hidden">
              <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest mb-8 flex items-center gap-2.5">
                 <Crown size={20} className="text-amber-500" /> Network Elites
              </h3>

              <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
                 {topShops.map((shop, i) => (
                    <motion.div 
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: i * 0.1 }}
                      key={i} 
                      className="flex items-center justify-between p-5 bg-white/40 dark:bg-slate-900/40 rounded-2xl border border-white/40 dark:border-white/5 group hover:bg-slate-900 hover:border-brand-primary/50 transition-all duration-500 cursor-default"
                    >
                       <div className="flex items-center gap-4">
                          <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-black shadow-xl shrink-0 ${i === 0 ? 'bg-amber-500 text-white shadow-amber-500/20' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}>
                             {i + 1}
                          </div>
                          <div className="min-w-0">
                             <p className="text-sm font-black text-slate-900 dark:text-white group-hover:text-white uppercase truncate italic leading-tight">{shop.name}</p>
                             <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">{shop.count} Settlements</p>
                          </div>
                       </div>
                       <div className="text-right shrink-0">
                          <p className="text-sm font-black text-white uppercase italic tracking-tighter break-all leading-none mb-2">₹{shop.revenue}</p>
                       </div>
                    </motion.div>
                 ))}
                 {topShops.length === 0 && (
                   <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                      <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center mb-6 opacity-30">
                         <Crown size={32} />
                      </div>
                      <p className="text-[10px] font-black uppercase tracking-widest italic">Scanning Network...</p>
                   </div>
                 )}
              </div>

              <Button 
                variant="ghost" 
                onClick={() => navigate('/admin/shops')} 
                className="mt-8 w-full h-12 !rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:bg-brand-primary/10 hover:text-brand-primary transition-all gap-2"
              >
                 Detailed Network Analysis
                 <ArrowUpRight size={14} />
              </Button>
           </GlassCard>
        </div>
      </div>

      {/* Activity and System Health Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2">
            <GlassCard intensity="high" className="p-10 border-white/40 dark:border-white/10">
               <div className="flex items-center justify-between mb-10">
                  <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2.5">
                     <AlertCircle size={20} className="text-brand-primary" /> Live Stream
                  </h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest italic">Mission Critical Logs</p>
               </div>

               <div className="space-y-4">
                  <AnimatePresence mode="popLayout">
                    {recentActivity.map((activity, idx) => (
                       <motion.div 
                         key={activity.id}
                         initial={{ opacity: 0, scale: 0.95 }}
                         animate={{ opacity: 1, scale: 1 }}
                         transition={{ delay: idx * 0.05 }}
                         className="flex items-center justify-between p-6 bg-white/20 dark:bg-slate-950/20 rounded-[1.75rem] border border-white/20 dark:border-white/5 group hover:border-brand-primary/30 transition-all duration-500"
                       >
                          <div className="flex items-center gap-5">
                             <div className="w-12 h-12 bg-white dark:bg-slate-900 text-brand-primary rounded-xl flex items-center justify-center shadow-lg border border-white/10 group-hover:scale-110 transition-transform">
                                <ShieldCheck size={22} />
                             </div>
                             <div>
                                <p className="text-base font-black text-slate-900 dark:text-white uppercase italic leading-tight">{activity.shop_name}</p>
                                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">{activity.plan_name} • Node Activated</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className="text-lg font-black text-brand-primary italic leading-none">+₹{activity.amount}</p>
                             <div className="flex items-center gap-1.5 justify-end mt-2">
                                <Clock size={10} className="text-slate-400" />
                                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">
                                   {new Date(activity.confirmed_at).toLocaleString('en-IN', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit', hour12: true })}
                                </p>
                             </div>
                          </div>
                       </motion.div>
                    ))}
                  </AnimatePresence>

                  {recentActivity.length === 0 && (
                    <div className="py-20 text-center">
                       <div className="w-20 h-20 bg-slate-100 dark:bg-slate-800 rounded-3xl flex items-center justify-center mx-auto mb-6 opacity-20 animate-pulse">
                          <ActivityIcon size={40} />
                       </div>
                       <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 italic">Awaiting Network Events...</p>
                    </div>
                  )}
               </div>
            </GlassCard>
        </div>

        {/* System Health Section */}
        <div className="space-y-8 h-full flex flex-col">
           <GlassCard intensity="high" className="p-10 border-white/10 bg-slate-900 dark:bg-slate-950 text-white shadow-2xl relative overflow-hidden flex-1 flex flex-col justify-between">
              <div className="relative z-10">
                 <div className="flex items-center justify-between mb-8">
                    <h3 className="text-xs font-black uppercase tracking-[0.2em] opacity-60">Engine Diagnostics</h3>
                    <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center border border-white/10">
                       <Zap size={20} className="text-brand-primary animate-pulse" />
                    </div>
                 </div>

                 <div className="space-y-5">
                    <div className="p-5 bg-white/5 rounded-2xl border border-white/5 group hover:bg-white/10 transition-colors">
                       <div className="flex items-center justify-between mb-3">
                          <span className="text-[10px] font-black uppercase tracking-widest opacity-80">Sync Bridge</span>
                          <span className="text-[9px] font-black text-brand-primary uppercase tracking-widest bg-brand-primary/10 px-2 py-1 rounded-lg">99.9% Up</span>
                       </div>
                       <div className="w-full h-1 bg-white/10 rounded-full overflow-hidden">
                          <motion.div initial={{ width: 0 }} animate={{ width: '99.9%' }} transition={{ duration: 2 }} className="h-full bg-brand-primary" />
                       </div>
                    </div>

                    <div className="p-5 bg-white/5 rounded-2xl border border-white/5 group hover:bg-white/10 transition-colors">
                       <div className="flex items-center justify-between mb-3">
                          <span className="text-[10px] font-black uppercase tracking-widest opacity-80">Compute Engine</span>
                          <span className="text-[9px] font-black text-brand-primary uppercase tracking-widest bg-brand-primary/10 px-2 py-1 rounded-lg">Optimal</span>
                       </div>
                       <div className="w-full h-1 bg-white/10 rounded-full overflow-hidden">
                          <motion.div initial={{ width: 0 }} animate={{ width: '12%' }} transition={{ duration: 2 }} className="h-full bg-brand-primary" />
                       </div>
                    </div>
                 </div>
              </div>

              <div className="mt-10 relative z-10">
                 <Button 
                   variant="ghost" 
                   onClick={() => navigate('/admin/settings')} 
                   className="w-full h-14 !rounded-2xl border border-white/10 text-white hover:bg-white/10 text-[10px] font-black uppercase tracking-[0.2em] transition-all gap-3"
                 >
                    Advanced Protocols
                    <Settings className="w-4 h-4" />
                 </Button>
              </div>

              {/* Liquid Orbs */}
              <div className="absolute -bottom-20 -right-20 w-64 h-64 bg-brand-primary/10 blur-[100px] rounded-full pointer-events-none" />
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-48 h-48 bg-indigo-500/10 blur-[100px] rounded-full pointer-events-none" />
           </GlassCard>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { supabase } from '../../lib/supabase';
import { 
  CreditCard, 
  Clock,
  Ban,
  ShieldCheck,
  X,
  Calendar,
  Sparkles,
  ArrowUpRight,
  TrendingUp,
  Receipt,
  Fingerprint
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';
import { useAuth } from '../../context/AuthContext';
import { useLanguage } from '../../context/LanguageContext';
import Button from '../../components/ui/Button';
import Input from '../../components/ui/Input';
import GlassCard from '../../components/ui/GlassCard';
import { formatIndianDateTime, addDurationDays } from '../../utils/dateUtils';

interface PendingPayment {
  id: string;
  shop_id: string;
  plan_id: number;
  amount: number;
  utr: string;
  duration_days: number;
  status: string;
  created_at: string;
  confirmed_at?: string;
  shop: { shop_name: string; shop_id: string };
  plan: { 
    name: string; 
    duration_days: number; 
  };
}

export default function AdminPayments() {
  const { user: adminUser } = useAuth();
  const { language } = useLanguage();
  const location = useLocation();
  const [payments, setPayments] = useState<PendingPayment[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'pending' | 'history'>(
    (location.state as any)?.tab || 'pending'
  );

  const [confirmingPayment, setConfirmingPayment] = useState<PendingPayment | null>(null);
  const [confirmForm, setConfirmForm] = useState({
    amount: 0,
    method: 'UPI',
    utr: ''
  });
  const [isProcessing, setIsProcessing] = useState(false);

  const fetchPayments = async () => {
    setLoading(true);
    try {
      if (activeTab === 'history') {
        const { data: historyData, error } = await supabase
          .from('payment_history')
          .select(`
            *,
            shop:shops_profile(shop_name, shop_id),
            plan:plans(name, duration_days)
          `)
          .order('confirmed_at', { ascending: false });

        if (error) throw error;
        setPayments(historyData as any[]);
        return;
      }

      const [paymentsRes, manualPendingRes] = await Promise.all([
        supabase.from('payments').select('*, shop:shops_profile(shop_name, shop_id), plan:plans(name, duration_days)').eq('status', 'pending').order('created_at', { ascending: false }),
        supabase.from('subscriptions').select('*, shop:shops_profile(shop_name, shop_id), plan:plans(name, duration_days)').eq('status', 'pending'),
      ]);

      if (paymentsRes.error) throw paymentsRes.error;

      const mergedData: any[] = [];
      (paymentsRes.data || []).forEach(p => mergedData.push({ ...p, type: 'payment' }));

      (manualPendingRes.data || []).forEach(sub => {
        if (!mergedData.find(m => m.shop_id === sub.shop_id)) {
          mergedData.push({ 
            id: `manual-${sub.id}`, 
            shop_id: sub.shop_id, 
            plan_id: sub.plan_id, 
            amount: 0, 
            utr: 'N/A', 
            status: 'pending', 
            created_at: sub.created_at, 
            type: 'manual', 
            shop: sub.shop, 
            plan: sub.plan 
          });
        }
      });
      setPayments(mergedData.sort((a,b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()));
    } catch (err: any) {
      console.error('Payments Fetch Error:', err);
      toast.error(`Sync Failure: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPayments();

    const channel = supabase.channel('admin-payments-sync')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'payments' }, () => fetchPayments())
      .on('postgres_changes', { event: '*', schema: 'public', table: 'payment_history' }, () => fetchPayments())
      .on('postgres_changes', { event: '*', schema: 'public', table: 'subscriptions' }, () => fetchPayments())
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [activeTab]);

  const openConfirmModal = (payment: PendingPayment) => {
    setConfirmingPayment(payment);
    setConfirmForm({
      amount: payment.amount || 0,
      method: 'UPI',
      utr: payment.utr || ''
    });
  };

  const processConfirmation = async () => {
    if (!confirmingPayment || !adminUser) return;
    setIsProcessing(true);

    try {
      const now = new Date();

      const { data: subData } = await supabase
        .from('subscriptions')
        .select('is_auto_mode, expiry_date')
        .eq('shop_id', confirmingPayment.shop_id)
        .single();

      const isAuto = subData?.is_auto_mode !== false;
      const currentExpiry = subData?.expiry_date;

      let finalExpiry = currentExpiry;
      const daysToAdd = confirmingPayment.duration_days || confirmingPayment.plan?.duration_days || 30;

      if (isAuto) {
        finalExpiry = addDurationDays(now, daysToAdd);
      }

      const { error: histErr } = await supabase.from('payment_history').insert([{
        shop_id: confirmingPayment.shop_id,
        admin_id: adminUser.id,
        amount: confirmForm.amount,
        payment_method: confirmForm.method,
        utr_number: confirmForm.utr,
        duration_days: daysToAdd,
        confirmed_at: now.toISOString(),
        status: 'confirmed',
        plan_id: confirmingPayment.plan_id
      }]);
      if (histErr) throw histErr;

      if (!confirmingPayment.id.startsWith('manual-')) {
        await supabase.from('payments').update({ 
          status: 'confirmed', 
          confirmed_at: now.toISOString() 
        }).eq('id', confirmingPayment.id);
      }

      const subUpdate: any = {
        shop_id: confirmingPayment.shop_id,
        plan_id: confirmingPayment.plan_id,
        status: 'active'
      };

      if (isAuto) {
        subUpdate.expiry_date = finalExpiry;
      }

      const { error: subErr } = await supabase.from('subscriptions').upsert(subUpdate, { onConflict: 'shop_id' });
      if (subErr) throw subErr;

      toast.success(isAuto ? `Transmission verified. Extended until ${finalExpiry.split('T')[0]}` : 'Transaction archived. Manual override respected.');

      setConfirmingPayment(null);
      fetchPayments();
    } catch (err: any) {
      console.error('Confirmation Error:', err);
      toast.error(`Authorization rejected: ${err.message}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReject = async (paymentId: string) => {
    if (!confirm('EXTERMINATE: Rejection will purge this transmission request. Continue?')) return;
    try {
      if (!paymentId.startsWith('manual-')) {
        await supabase.from('payments').update({ status: 'rejected' }).eq('id', paymentId);
      }
      toast.error('Transmission purged');
      fetchPayments();
    } catch (err) {
      toast.error('Operation failed');
    }
  };

  return (
    <div className="space-y-10 pb-10">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
           <motion.h1 
             initial={{ opacity: 0, x: -20 }}
             animate={{ opacity: 1, x: 0 }}
             className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter uppercase italic leading-none"
           >
             Financial <span className="text-brand-primary">Nexus</span>
           </motion.h1>
           <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px] mt-3 flex items-center gap-2">
             <TrendingUp size={12} className="text-brand-primary" />
             Transaction Streams & Activation Center
           </p>
        </div>

        <div className="flex p-1.5 bg-white/40 dark:bg-slate-950/40 backdrop-blur-xl border border-white/20 dark:border-white/5 rounded-2xl shadow-inner w-fit">
          <button 
            onClick={() => setActiveTab('pending')}
            className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'pending' ? 'bg-brand-primary text-white shadow-glow-green font-black' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-300'}`}
          >
            Pending
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'history' ? 'bg-brand-primary text-white shadow-glow-green font-black' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-300'}`}
          >
            Confirmed
          </button>
        </div>
      </div>

      {loading ? (
        <div className="space-y-4">
           {[1,2,3].map(i => <GlassCard key={i} intensity="low" className="h-28 animate-pulse border-white/10" />)}
        </div>
      ) : payments.length === 0 ? (
        <GlassCard intensity="low" className="py-24 border-dashed border-2 border-white/20 text-center space-y-6">
           <div className="w-20 h-20 bg-white/5 rounded-[2.5rem] flex items-center justify-center mx-auto opacity-20">
              <CreditCard size={40} className="text-slate-400" />
           </div>
           <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 italic">No transaction streams detected</p>
        </GlassCard>
      ) : (
        <div className="grid grid-cols-1 gap-5">
          <AnimatePresence mode="popLayout">
            {payments.map((payment: PendingPayment, i) => (
              <motion.div
                key={payment.id}
                layout
                initial={{ opacity: 0, scale: 0.98, y: 10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                transition={{ delay: i * 0.03 }}
              >
                <GlassCard
                  intensity="low"
                  className="p-6 border-white/40 dark:border-white/5 flex flex-col md:flex-row md:items-center justify-between group hover:border-brand-primary/20 transition-all relative overflow-hidden"
                >
                  <div className="flex items-center gap-6">
                    <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center transition-all border shadow-inner ${payment.status === 'confirmed' ? 'bg-brand-primary/10 text-brand-primary border-brand-primary/20' : 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20'}`}>
                      {payment.status === 'confirmed' ? <ShieldCheck size={28} /> : <Clock size={28} />}
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter italic leading-none group-hover:text-brand-primary transition-colors">{payment.shop?.shop_name}</h3>
                      <div className="flex items-center gap-3 mt-3">
                          <span className="text-[10px] font-black text-brand-primary uppercase tracking-widest">{payment.plan?.name} Tier</span>
                          <div className="w-1 h-1 bg-brand-primary/20 rounded-full" />
                          <span className="text-[10px] font-black text-brand-secondary uppercase tracking-widest">{payment.duration_days || 30} Days</span>
                          <div className="w-1 h-1 bg-brand-primary/20 rounded-full" />
                          <span className="text-[10px] font-black text-slate-900 dark:text-white uppercase italic tracking-tighter text-lg">₹{payment.amount}</span>
                       </div>
                    </div>
                  </div>

                  <div className="mt-6 md:mt-0 flex items-center gap-10 lg:gap-16">
                     <div className="text-right hidden lg:block">
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center justify-end gap-2">
                           <Fingerprint size={10} /> Transmission Hash
                        </p>
                        <p className="text-xs font-mono font-black text-slate-800 dark:text-slate-200 tracking-tighter">{payment.utr || (payment as any).payment_method || 'ANONYMOUS'}</p>
                     </div>

                     <div className="text-right">
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center justify-end gap-2 text-right">
                          <Calendar size={10} /> {payment.status === 'pending' ? 'Initiated' : 'Finalized'}
                        </p>
                        <p className="text-xs font-black text-slate-600 dark:text-slate-400 uppercase tracking-tighter">
                          {formatIndianDateTime(payment.confirmed_at || payment.created_at, language)}
                        </p>
                     </div>

                     {activeTab === 'pending' && (
                       <div className="flex gap-3">
                          <Button 
                            variant="ghost" 
                            onClick={() => handleReject(payment.id)} 
                            className="w-12 h-12 !p-0 !rounded-xl bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white border border-red-500/10"
                          >
                             <Ban size={18} />
                          </Button>
                          <Button 
                            onClick={() => openConfirmModal(payment)} 
                            className="h-14 px-8 !rounded-2xl shadow-glow-green" 
                            variant="primary"
                          >
                             Authorize <ArrowUpRight size={16} className="ml-2" />
                          </Button>
                       </div>
                     )}

                     {activeTab === 'history' && (
                        <div className="w-12 h-12 rounded-xl bg-brand-primary/5 flex items-center justify-center text-brand-primary/30 rotate-12">
                           <Receipt size={24} />
                        </div>
                     )}
                  </div>

                  {/* Aesthetic Background Gradient */}
                  <div className={`absolute top-0 right-0 w-32 h-full -z-10 blur-[80px] opacity-10 transition-colors ${
                    payment.status === 'confirmed' ? 'bg-brand-primary' : 'bg-brand-secondary'
                  }`} />
                </GlassCard>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>
      )}

      {/* CONFIRMATION MODAL */}
      <AnimatePresence>
         {confirmingPayment && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl"
                 onClick={() => !isProcessing && setConfirmingPayment(null)}>
               <motion.div 
                  initial={{ scale: 0.95, opacity: 0, y: 30 }}
                  animate={{ scale: 1, opacity: 1, y: 0 }}
                  exit={{ scale: 0.95, opacity: 0, y: 30 }}
                  onClick={(e) => e.stopPropagation()}
                  className="w-full max-w-md overflow-hidden"
               >
                  <GlassCard intensity="high" className="border-white/20 dark:border-white/10 shadow-[0_0_100px_rgba(0,0,0,0.5)]">
                     <div className="p-10 text-center border-b border-white/10 relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-brand-primary opacity-5 blur-[40px] rounded-full" />
                        <Button 
                          variant="ghost" 
                          onClick={() => setConfirmingPayment(null)} 
                          className="absolute top-6 right-6 w-10 h-10 !p-0 !rounded-xl text-white/40 hover:text-white"
                        >
                           <X size={18} />
                        </Button>
                        <div className="w-20 h-20 bg-brand-primary/10 rounded-[2.5rem] flex items-center justify-center mx-auto mb-6 border border-brand-primary/20 shadow-glow-green/10">
                           <CreditCard className="text-brand-primary" size={40} />
                        </div>
                        <h2 className="text-2xl font-black text-slate-900 dark:text-white italic uppercase tracking-tighter">Authorize Stream</h2>
                        <div className="flex items-center justify-center gap-2 mt-3">
                           <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Destination Hub:</span>
                           <span className="text-[10px] font-black text-brand-primary uppercase tracking-widest">{confirmingPayment.shop?.shop_name}</span>
                        </div>
                     </div>

                     <div className="p-10 space-y-8">
                         <div className="grid grid-cols-2 gap-6">
                           <Input 
                             label="Validated Amount (₹)" 
                             type="number" 
                             value={confirmForm.amount} 
                             onChange={(e) => setConfirmForm({...confirmForm, amount: Number(e.target.value)})}
                           />
                           <div className="space-y-3">
                              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Route</label>
                              <select 
                                value={confirmForm.method}
                                onChange={(e) => setConfirmForm({...confirmForm, method: e.target.value})}
                                className="w-full h-14 px-5 bg-white/30 dark:bg-slate-900/50 border-2 border-white/20 dark:border-white/10 rounded-2xl text-xs font-black uppercase tracking-widest outline-none focus:border-brand-primary transition-all appearance-none cursor-pointer"
                              >
                                 <option value="UPI" className="bg-slate-900">UPI Digital</option>
                                 <option value="Cash" className="bg-slate-900">Physical Cash</option>
                                 <option value="Bank" className="bg-slate-900">Swift/Bank</option>
                              </select>
                           </div>
                         </div>

                         <Input 
                           label="Protocol Verification (UTR/Hash)" 
                           value={confirmForm.utr} 
                           onChange={(e) => setConfirmForm({...confirmForm, utr: e.target.value})}
                           placeholder="Enter Validation Hash"
                         />

                         <div className="bg-brand-secondary/5 border border-brand-secondary/20 p-6 rounded-[2rem] flex items-start gap-4">
                            <Sparkles className="text-brand-secondary shrink-0 mt-1" size={20} />
                             <p className="text-[10px] font-black text-brand-secondary uppercase leading-relaxed tracking-widest">
                               Verification will initialize a **{confirmingPayment.duration_days || 30} Day Cycle** extension on the target nexus.
                             </p>
                         </div>

                         <div className="flex gap-4 pt-4">
                            <Button variant="ghost" className="flex-1 h-14 !rounded-2xl font-black uppercase tracking-widest text-slate-500" onClick={() => setConfirmingPayment(null)}>Abort</Button>
                            <Button className="flex-2 h-14 !rounded-2xl shadow-glow-green" variant="primary" disabled={isProcessing} onClick={processConfirmation}>
                               {isProcessing ? 'Verifying Cipher...' : 'Authorize Activation ✓'}
                            </Button>
                         </div>
                     </div>
                  </GlassCard>
               </motion.div>
            </div>
         )}
      </AnimatePresence>
    </div>
  );
}

import { useEffect, useState, useRef, useCallback, useMemo } from 'react';
import { supabase } from '../../lib/supabase';
import { 
  createProofAndDeletePersonalData, 
  performPrivacyAudit, 
  purgeStalePendingOrders, 
  cleanupOldOrders,
  archiveAndCleanupCloudOrders
} from '../../utils/privacyProof';
import OrderModal from '../../components/shopkeeper/OrderModal';
import ProofModal from '../../components/shopkeeper/ProofModal';
import MultiQRGenerator from '../../components/shopkeeper/MultiQRGenerator';
import QRCode from 'qrcode';
import { toast } from 'sonner';
import db from '../../db/dexie';
import type { ShopProfile, PendingOrder, OrderHistory, OrderItem, MenuItem } from '../../db/dexie';
import { useAuth } from '../../context/AuthContext';
import { useSubscription } from '../../context/SubscriptionContext';
import {
  LogOut, QrCode, ListOrdered, History, Download, Copy, Printer,
  Bell, BellOff, PackageOpen, IndianRupee,
  Sun, Moon, UtensilsCrossed, Plus, Trash2, Sparkles,
  TrendingUp, Lock, Shield, ShieldCheck, Settings, ShieldAlert,
  Megaphone
} from 'lucide-react';
import { isExpired, isExpiringSoon, getFormattedRemainingTime } from '../../utils/dateUtils';
import VoiceSettings from '../../components/shopkeeper/VoiceSettings';
import { useTheme } from '../../context/ThemeContext';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Skeleton from '../../components/ui/Skeleton';
import Input from '../../components/ui/Input';
import Button from '../../components/ui/Button';
import { decrypt } from '../../utils/encryption';
import OrderCard from '../../components/shopkeeper/OrderCard';
import GlassCard from '../../components/ui/GlassCard';
import { useAntiCapture } from '../../hooks/useAntiCapture';
import ProtectionOverlay from '../../components/ui/ProtectionOverlay';
import SecureCanvas from '../../components/ui/SecureCanvas';
import haptics from '../../utils/haptics';
import useSound from '../../hooks/useSound';
import PullToRefresh from '../../components/ui/PullToRefresh';
import { useVoice } from '../../context/VoiceContext';
import { exportBackup, downloadJSON, importBackup } from '../../utils/backup';
import DailySalesReport from '../../components/shopkeeper/DailySalesReport';
import { useLanguage } from '../../context/LanguageContext';
import LanguageSwitcher from '../../components/ui/LanguageSwitcher';
import AdBanner from '../../components/ui/AdBanner';
import SessionManager from '../../components/settings/SessionManager';

const SpeechRecognition =
  (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

type Tab = 'orders' | 'history' | 'qr' | 'report' | 'menu' | 'settings';

export default function Dashboard() {
  const { user, logout, isAdmin } = useAuth();
  const { subscription, hasFeature, loading: subLoading } = useSubscription();
  const { theme, toggleTheme } = useTheme();
  const { t, language } = useLanguage();
  const { playNotification } = useSound();
  const { speak, announceOrder } = useVoice();
  const navigate = useNavigate();

  // Profile
  const [profile, setProfile] = useState<ShopProfile | null>(null);
  const [loading, setLoading] = useState(true);

  // Assistant
  const [isAssistantListening, setIsAssistantListening] = useState(false);

  const handleAssistantVoice = () => {
    if (!SpeechRecognition) {
      toast.error(t('customer.voiceNotSupported'));
      return;
    }
    const rec = new SpeechRecognition();
    rec.lang = 'hi-IN';
    rec.onstart = () => {
      setIsAssistantListening(true);
      haptics.light();
    };
    rec.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript.toLowerCase();

      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const todayOrders = await db.orderHistory.where('completedAt').above(today.getTime()).toArray();

      const totalSale = todayOrders.reduce((sum, o) => sum + o.total, 0);
      const orderCount = todayOrders.length;

      if (transcript.includes('sale') || transcript.includes('kamai') || transcript.includes('बिक्री') || transcript.includes('कमाई')) {
        const text = language === 'hi' 
          ? `Aaj ki kul bikri ${totalSale} rupaye hai aur aapne ${orderCount} order poore kiye hain.` 
          : `Today's total sale is ${totalSale} rupees from ${orderCount} orders.`;
        toast(text, { icon: <TrendingUp className="text-kirana-green" /> });
        setTab('report');
      } else if (transcript.includes('order') || transcript.includes('ऑर्डर')) {
        const text = language === 'hi' 
          ? `अभी आपके पास ${pending.length} पेंडिंग ऑर्डर हैं।` 
          : `You have ${pending.length} pending orders right now.`;
        speak(text);
        setTab('orders');
      } else {
        toast.error(language === 'hi' ? 'Kshama karein, mujhe samajh nahi aaya.' : "Sorry, I didn't get that.");
      }
    };
    rec.onerror = () => setIsAssistantListening(false);
    rec.onend = () => setIsAssistantListening(false);
    rec.start();
  };

  // Orders
  const [pending, setPending] = useState<PendingOrder[]>([]);
  const [history, setHistory] = useState<OrderHistory[]>([]);
  const [selectedOrder, setSelectedOrder] = useState<PendingOrder | null>(null);
  const [selectedHistoryOrder, setSelectedHistoryOrder] = useState<OrderHistory | null>(null);

  // UI
  const [tab, setTab] = useState<Tab>('orders');
  const [historySearch, setHistorySearch] = useState('');
  const [historyFilter, setHistoryFilter] = useState<'all' | 'completed' | 'rejected'>('all');
  const [autoAnnounce, setAutoAnnounce] = useState(true);
  const [announcements, setAnnouncements] = useState<any[]>([]);
  const [isGeneratingMultiQR, setIsGeneratingMultiQR] = useState(false);
  const { isBlocked, isPenaltyActive, strikeCount } = useAntiCapture(tab === 'orders' || tab === 'history');

  useEffect(() => {
    fetchAnnouncements();
    const annSub = supabase.channel('announcements')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'announcements' }, () => {
        fetchAnnouncements();
      })
      .subscribe();

    // TC-080: Profile Realtime Sync
    const profileSub = supabase.channel('profile-sync')
      .on('postgres_changes', { 
        event: 'UPDATE', 
        schema: 'public', 
        table: 'shops_profile',
        filter: `id=eq.${user?.id}`
      }, async (payload) => {
        const updatedProfile = payload.new as ShopProfile;
        setProfile(updatedProfile);
        await db.shopProfile.put(updatedProfile);
        toast.success(language === 'hi' ? 'प्रोफ़ाइल अपडेट हो गई!' : 'Profile updated live!');
      })
      .subscribe();

    return () => { 
      supabase.removeChannel(annSub); 
      supabase.removeChannel(profileSub); 
    };
  }, [user?.id, language]);

  const fetchAnnouncements = async () => {
    const { data } = await supabase
      .from('announcements')
      .select('*')
      .order('created_at', { ascending: false });
    if (data) setAnnouncements(data);
  };

  const handleSupport = () => {
    window.open('https://wa.me/917349141040?text=Hello%20Order-Do%20Support!', '_blank');
    haptics.light();
  };

  // Menu Management
  const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
  const [newMenuItem, setNewMenuItem] = useState({ name: '', price: '', category: '', description: '' });
  const [isAddingMenu, setIsAddingMenu] = useState(false);
  const [isMenuSaving, setIsMenuSaving] = useState(false);

  // QR
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const lastPendingCountRef = useRef(0);

  // Load profile
  useEffect(() => {
    const load = async () => {
      // 1. Run Privacy Audit (Cleanup) on load
      try {
          await performPrivacyAudit();
          await cleanupOldOrders(); // 30-day cloud cleanup
          await purgeStalePendingOrders(4); // Immediate session cleanup (4h)

          // 2. Check for Archival (Cloud -> CSV)
          const THIRTY_DAYS_MS = 30 * 24 * 60 * 60 * 1000;
          const thirtyDaysAgo = new Date(Date.now() - THIRTY_DAYS_MS).toISOString();
          const { count } = await supabase
            .from('pending_orders')
            .select('*', { count: 'exact', head: true })
            .lt('created_at', thirtyDaysAgo);

          if (count && count > 0) {
            toast(t('REPORT_ARCHIVE_READY'), {
              duration: 10000,
              icon: <ShieldAlert className="text-kirana-orange" />,
              action: {
                label: t('REPORT_ARCHIVE_ACTION'),
                onClick: async () => {
                  try {
                    await archiveAndCleanupCloudOrders();
                    speak(t('REPORT_ARCHIVE_SUCCESS'));
                    toast.success(t('REPORT_ARCHIVE_SUCCESS'));
                  } catch (err) {
                    toast.error('Archival failed');
                  }
                }
              }
            });
          }
      } catch (err) {
          console.warn('[Dashboard] Privacy audit failed:', err);
      }

      const profiles = await db.shopProfile.toArray();
      let p = profiles.find((x) => x.id === user?.id) || profiles[profiles.length - 1];

      if (!p && !user?.id) {
        return; 
      }

      if (!p) {
        const all = await db.shopProfile.toArray();
        if (all.length > 0) {
          p = all[all.length - 1];
        }
      }

      if (!p) {
        navigate('/shop/setup');
      } else {
        setProfile(p);

        // Load Menu (Sync Cloud -> Local)
        try {
          const { data: cloudItems } = await supabase
            .from('menu_items')
            .select('*')
            .eq('shop_id', user?.id);

          if (cloudItems && cloudItems.length > 0) {
            // Surgical Sync: Update local with cloud data without deleting local-only additions
            for (const ci of cloudItems) {
               const existing = await db.menuItems
                 .where('shopId').equals(p.shopId)
                 .and(m => m.name === ci.name)
                 .first();

               await db.menuItems.put({
                 ...ci,
                 id: existing?.id, // Preserve local ID for auto-increment consistency
                 shopId: p!.shopId,
                 available: ci.available !== false
               });
            }
            const finalItems = await db.menuItems.where('shopId').equals(p.shopId).toArray();
            setMenuItems(finalItems);
          } else {
            // If cloud is empty but local has data, sync local -> cloud
            const localItems = await db.menuItems.where('shopId').equals(p.shopId).toArray();
            if (localItems.length > 0 && user?.id) {
               await supabase.from('menu_items').insert(
                 localItems.map(({ id, ...item }) => ({
                   ...item,
                   shop_id: user.id
                 }))
               );
            }
            setMenuItems(localItems);
          }
        } catch (mErr) {
          console.error('[Dashboard] Menu sync failed:', mErr);
          const items = await db.menuItems.where('shopId').equals(p.shopId).toArray();
          setMenuItems(items);
        }

        const welcomeText = language === 'hi' 
          ? `Namaste! ${p.shopName} mein swagat hai.` 
          : `Welcome to ${p.shopName}!`;

        toast(welcomeText, { icon: <Sparkles className="text-kirana-green" /> });
        speak(welcomeText);
      }
      setLoading(false);
    };
    load();
  }, [user, navigate, language]);

  // Refresh
  const refreshOrders = useCallback(async () => {
    if (!profile) return;
    const p = await db.pendingOrders
      .where('shopId')
      .equals(profile.shopId)
      .reverse()
      .sortBy('createdAt');

    // Decrypt names for display (Async)
    const decryptedP = await Promise.all(p.map(async (o) => ({
      ...o,
      decryptedName: o.customerName === 'DELETED_FOR_PRIVACY' ? 'Customer' : await decrypt(o.customerName, profile.shopId)
    })));

    if (autoAnnounce && decryptedP.length > lastPendingCountRef.current && lastPendingCountRef.current > 0) {
      const newest = decryptedP[0] as any;
      if (newest) {
        playNotification();
        haptics.warning();
        const customerNameDisplay = newest.decryptedName;
        const orderAlertText = language === 'hi' 
          ? `Naya order aaya hai! ऑडर्र नंबर ${newest.short_id || ''} ${customerNameDisplay} ने भेजा है।` 
          : `New order #${newest.short_id || ''} arrived from ${customerNameDisplay}!`;

        announceOrder(customerNameDisplay, newest.items, newest.short_id || 'NEW', newest.type, newest.no);
        toast(orderAlertText, { icon: <Bell className="text-kirana-orange" /> });
      }
    }
    lastPendingCountRef.current = decryptedP.length;
    setPending(decryptedP as any[]);

    const h = await db.orderHistory
      .where('shopId')
      .equals(profile.shopId)
      .reverse()
      .sortBy('completedAt');

    // Decrypt history names
    const decryptedH = await Promise.all(h.map(async (o) => ({
      ...o,
      decryptedName: o.customerName === 'DELETED_FOR_PRIVACY' ? 'Customer' : await decrypt(o.customerName, profile.shopId)
    })));

    setHistory(decryptedH as any[]);
  }, [profile, autoAnnounce, playNotification, t, language, speak]);

  const filteredHistory = useMemo(() => {
    return history.filter((h: any) => {
      const isStatusMatch = historyFilter === 'all' || h.status === historyFilter;
      if (!isStatusMatch) return false;

      if (!historySearch) return true;
      const term = historySearch.toLowerCase();
      const customerNameDisplay = h.decryptedName?.toLowerCase() || '';
      const itemsMatch = h.items.some((i: any) => i.name.toLowerCase().includes(term));
      const idMatch = h.id.toLowerCase().includes(term) || (h.orderToken && h.orderToken.toLowerCase().includes(term));

      return customerNameDisplay.includes(term) || itemsMatch || idMatch;
    });
  }, [history, historySearch, historyFilter]);

  useEffect(() => {
    if (!profile) return;
    refreshOrders();

    // Real-time Cloud Sync
    const channel = supabase.channel(`dashboard-orders-${profile.shopId}`)
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'pending_orders',
        filter: `shop_id=eq.${profile.shopId}`
      }, async (payload) => {
        if (payload.eventType === 'INSERT') {
          const cloudOrder = payload.new as any;
          // Sync to local Dexie
          await db.pendingOrders.put({
            id: cloudOrder.id,
            shopId: cloudOrder.shop_id,
            customerName: cloudOrder.customer_name,
            customerAddress: cloudOrder.customer_address,
            customerPhone: cloudOrder.customer_phone,
            photoDataUrl: cloudOrder.photo_data_url,
            items: cloudOrder.items,
            createdAt: new Date(cloudOrder.created_at).getTime(),
            status: cloudOrder.status,
            type: cloudOrder.type,
            no: cloudOrder.no,
            paymentStatus: cloudOrder.payment_status,
            paymentReceived: cloudOrder.payment_received,
          });
          refreshOrders();
        } else {
          refreshOrders();
        }
      })
      .subscribe();

    const interval = setInterval(refreshOrders, 5000); // Polling as fallback (5s)

    // Privacy Interval: Force purge stale data every 15 minutes
    const privacyInterval = setInterval(() => {
        purgeStalePendingOrders(6);
    }, 15 * 60 * 1000);

    return () => {
        supabase.removeChannel(channel);
        clearInterval(interval);
        clearInterval(privacyInterval);
    };
  }, [profile, refreshOrders]);

  // Menu actions
  const handleAddMenuItem = async () => {
    if (!profile || !user || !newMenuItem.name || !newMenuItem.price || isMenuSaving) return;
    setIsMenuSaving(true);
    try {
      const itemData = {
        shopId: profile.shopId,
        name: newMenuItem.name,
        price: parseFloat(newMenuItem.price),
        description: newMenuItem.description || undefined,
        category: newMenuItem.category || undefined,
        available: true
      };

      // 1. Add to Cloud
      const { data, error } = await supabase
        .from('menu_items')
        .insert([{ ...itemData, shop_id: user.id }])
        .select()
        .single();

      if (error) throw error;

      // 2. Add to Local
      await db.menuItems.add({ ...itemData, id: data.id });
      setMenuItems([...menuItems, { ...itemData, id: data.id }]);
      setNewMenuItem({ name: '', price: '', category: '', description: '' });
      setIsAddingMenu(false);
      toast.success(t('setup.menu.saveMenu') || 'Item added');
      haptics.success();
    } catch (err) {
      console.error(err);
      toast.error('Error adding item');
    } finally {
      setIsMenuSaving(true);
      setTimeout(() => setIsMenuSaving(false), 2000); // 2 second debounce
    }
  };

  const handleDeleteMenuItem = async (id: number) => {
    if (!confirm('Delete this item?')) return;
    try {
       // Delete from cloud
       await supabase.from('menu_items').delete().eq('id', id);
       // Delete from local
       await db.menuItems.delete(id);
       setMenuItems(menuItems.filter(m => m.id !== id));
       toast.success('Item removed');
       haptics.warning();
    } catch (err) {
       toast.error('Delete failed');
    }
  };

  const toggleMenuItemAvailability = async (item: MenuItem) => {
    if (!item.id) return;
    const newStatus = !item.available;
    try {
       // Optimistic update
       setMenuItems(prev => prev.map(m => m.id === item.id ? { ...m, available: newStatus } : m));

       // Update cloud
       const { error } = await supabase
         .from('menu_items')
         .update({ available: newStatus })
         .eq('id', item.id);

       if (error) throw error;

       // Update local
       await db.menuItems.update(item.id, { available: newStatus });
       haptics.light();
    } catch (err) {
       toast.error('Sync failed');
       // Rollback
       setMenuItems(prev => prev.map(m => m.id === item.id ? { ...m, available: item.available } : m));
    }
  };

  // QR actions
  const handleGenerateExtraQRs = async (items: { type: 'counter' | 'table'; no: string; code: string }[]) => {
    if (!profile) return;
    const updatedExtras = [...(profile.extraQRs || []), ...items];
    const uniqueExtras = Array.from(new Set(updatedExtras.map(ex => `${ex.type}-${ex.no}`)))
      .map(key => {
        const entry = updatedExtras.find(ex => `${ex.type}-${ex.no}` === key)!;
        return { type: entry.type, no: entry.no, code: entry.code };
      });

    await db.shopProfile.update(profile.id, { extraQRs: uniqueExtras });
    const historyEntries = items.map(it => ({
      code: it.code,
      shopId: profile.shopId,
      type: it.type,
      no: it.no,
      createdAt: Date.now()
    }));
    await db.qrHistory.bulkAdd(historyEntries);
    setProfile({ ...profile, extraQRs: uniqueExtras });
    toast.success(t('dashboard.generateAll'));
    haptics.success();
  };

  const handleDeleteExtraQR = async (type: string, no: string) => {
    if (!profile || !profile.extraQRs) return;
    const filtered = profile.extraQRs.filter(ex => !(ex.type === type && ex.no === no));
    await db.shopProfile.update(profile.id, { extraQRs: filtered });
    setProfile({ ...profile, extraQRs: filtered });
    haptics.warning();
  };

  useEffect(() => {
    let retryCount = 0;
    const maxRetries = 5;

    const render = () => {
      if (profile && tab === 'qr') {
        if (canvasRef.current) {
          const codeParam = profile.masterQrCode ? `&code=${profile.masterQrCode}` : '';
          const url = `${window.location.origin}/order?shop=${profile.shopId}${codeParam}`;
          QRCode.toCanvas(canvasRef.current, url, {
            width: 300,
            margin: 2,
            color: { dark: '#0f172a', light: '#ffffff' },
          }, (err) => {
            if (err) console.error('[QR] Render failed:', err);
          });
        } else if (retryCount < maxRetries) {
          retryCount++;
          setTimeout(render, 200);
        }
      }
    };

    render();
  }, [profile, tab]);

  // Order actions
  const handleUpdateStatus = async (orderId: string, status: 'pending' | 'accepted' | 'rejected' | 'ready') => {
    try {
      // 1. Update Supabase (Realtime bridge)
      const { error: syncError } = await supabase
        .from('pending_orders')
        .update({ status })
        .eq('id', orderId);

      if (syncError) throw syncError;

      // 2. Update local Dexie for offline consistency
      await db.pendingOrders.update(orderId, { status });

      toast.success(t('dashboard.statusUpdated'));
      haptics.light();
      await refreshOrders();
    } catch (err: any) {
      console.error('[Dashboard] Status Update Failed:', err);
      toast.error('Sync failed: ' + err.message);
    }
  };

  const handleOrderDone = async (order: PendingOrder, pricedItems: OrderItem[], total: number, paymentReceived: boolean) => {
    const customerNameDisplay = (order as any).decryptedName || 'Customer';

    // Create Proof and Delete Personal Data (New System)
    try {
        const result = await createProofAndDeletePersonalData(order.id, total);
        console.log(`[Dashboard] PrivacyProof success for ${order.id}. Token: ${result.orderToken}`);

        setSelectedOrder(null);
        toast.success(t('dashboard.orderComplete').replace('[name]', customerNameDisplay).replace('[total]', total.toString()));
        haptics.success();
        await refreshOrders();
    } catch (err) {
        console.error('[Dashboard] Error during order finalization:', err);
        toast.error('PrivacyProof generation failed. Still marking as done.');

        // Fallback: If proof generation fails, still mark it done in the old way
        await db.orderHistory.put({
          id: order.id,
          shopId: order.shopId,
          customerName: order.customerName,
          customerAddress: order.customerAddress,
          photoDataUrl: order.photoDataUrl,
          items: pricedItems,
          total,
          status: 'completed',
          createdAt: order.createdAt,
          completedAt: Date.now(),
          paymentStatus: order.paymentStatus,
          paymentReceived: paymentReceived,
          type: order.type,
          no: order.no,
        });
        await db.pendingOrders.delete(order.id);
