function QRItem({ shopId, type, no, code }: { shopId: string; type: string; no: string; code: string }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    if (canvasRef.current) {
      const url = `${window.location.origin}/order?shop=${shopId}&type=${type}&no=${no}&code=${code}`;
      QRCode.toCanvas(canvasRef.current, url, { width: 140, margin: 1 });
    }
  }, [shopId, type, no, code]);
  return (
    <div onClick={() => {
      if (!canvasRef.current) return;
      const link = document.createElement('a');
      link.download = `QR-${type}-${no}.png`;
      link.href = canvasRef.current.toDataURL();
      link.click();
      haptics.light();
    }} className="cursor-pointer active:scale-95 transition-transform">
      <canvas ref={canvasRef} className="rounded-lg shadow-sm w-full" />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ShieldAlert, LogOut, Smartphone, Terminal, RefreshCcw, ArrowRight } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { getDeviceId } from '../../utils/deviceInfo';
import GlassCard from '../../components/ui/GlassCard';
import Button from '../../components/ui/Button';
import Loader from '../../components/ui/Loader';

export default function DeviceLimit() {
  const { user, logout } = useAuth();
  const [sessions, setSessions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const currentDeviceId = getDeviceId();

  const fetchSessions = async () => {
    if (!user) return;
    setLoading(true);
    const { data, error } = await supabase
      .from('user_sessions')
      .select('*')
      .eq('user_id', user.id)
      .order('last_active_at', { ascending: false });

    if (!error) setSessions(data || []);
    setLoading(false);
  };

  useEffect(() => {
    fetchSessions();
  }, [user]);

  const handleDeactivate = async (sessionId: string) => {
    setActionLoading(sessionId);
    const { error } = await supabase
      .from('user_sessions')
      .delete()
      .eq('id', sessionId);

    if (!error) {
      await fetchSessions();
      // If we deactivated another device, we might be able to reload now
      if (sessions.length <= 1) { // This is just a UI hint
         window.location.reload();
      }
    }
    setActionLoading(null);
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-slate-950"><Loader /></div>;

  return (
    <div className="min-h-screen bg-slate-950 text-white selection:bg-brand-primary/30 flex items-center justify-center p-6 relative overflow-hidden">
      {/* Aesthetic Background */}
